1963	/// From inside the enclave, the entry port should be unreachable on the sentry.
1964	pub fn sortie_net_dnat_entry_reflection(_extra_args: &[&str]) -> rbida_Verdict {
1965	    let sentry_ip = match env_require("RBRN_ENCLAVE_SENTRY_IP") {
