1973	        },
1974	        Err(e) => return fail(format!("ERROR: {}", e)),
1975	    };
1976	    let enc_port: u16 = match env_require("RBRN_ENTRY_PORT_ENCLAVE") {
1977	        Ok(v) => match v.parse() {
1978	            Ok(p) => p,
1979	            Err(_) => return fail(format!("ERROR: bad RBRN_ENTRY_PORT_ENCLAVE: {}", v)),
1980	        },
1981	        Err(e) => return fail(format!("ERROR: {}", e)),
1982	    };
1983	
1984	    let timeout = Duration::from_secs(2);
1985	    let mut diagnostics = Vec::new();
1986	
1987	    // Test 1: Workstation-facing entry port on sentry (the DNAT target)
