2016	            sentry_ip,
2017	            enc_port,
2018	            if enc_refused { "refused" } else { "timeout" },
2019	            enc_err.as_deref().unwrap_or("clean timeout")
2020	        ));
2021	    }
2022	
2023	    // Test 3: Verify the bottle's own enclave IP doesn't expose the entry port
2024	    // (DNAT should not reflect back to the bottle itself)
2025	    if let Ok(bottle_ip) = env_require("RBRN_ENCLAVE_BOTTLE_IP") {
2026	        let (bottle_connected, bottle_refused, bottle_err) = tcp_probe(&bottle_ip, enc_port, timeout);
